20	/** @file*/
21	
22	#include "internal_nn_math.h"
23	#include "riscv_nn_support.h"
24	
25	//// Convolution Functions
26	
27	int32_t riscv_nn_conv_dw_HWC_u8_u8_u8_asym_bias_any(const uint8_t * in_tensor,
28	                                                    const uint16_t in_tensor_dim_x,
29	                                                    const uint16_t in_tensor_dim_y,
30	                                                    const uint16_t in_tensor_ch,
31	                                                    const uint8_t * ker_weight,
32	                                                    const uint16_t ker_dim_x,
33	                                                    const uint16_t ker_dim_y,
34	                                                    const int16_t ch_mult,
35	                                                    const int16_t pad_x,
36	                                                    const int16_t pad_y,
37	                                                    const int16_t stride_x,
38	                                                    const int16_t stride_y,
39	                                                    const int16_t dilation_x,
40	                                                    const int16_t dilation_y,
41	                                                    const int32_t * bias,
42	                                                    const int32_t in_offset,    //assume (in + offset) is in the range of int16
43	                                                    const int32_t ker_offset,   //assume (kernel + offset) is in the range of int16
44	                                                    const int32_t out_offset,   //assume (output + offset) is in the range of int16
45	                                                    uint8_t * out_tensor,
46	                                                    const uint16_t out_tensor_dim_x,
47	                                                    const uint16_t out_tensor_dim_y,
48	                                                    const int32_t act_min,
49	                                                    const int32_t act_max,
50	                                                    const int32_t out_shift,
51	                                                    const int32_t out_scale)
52	{
53	    int32_t status = 0;
54	
55	#ifdef ENA_EMPTY_FUN
56	    //empty body
57	#else
58	    //check input constraints
59	    if((ch_mult & 1) || (ker_dim_x & 1))
60	    {
61	        return -1;
62	    }
63	    //to be checked: it seems pad_x must be even
64	    // if(pad_x & 1)
65	    // {
66	    //     return 1;
67	    // }
68	#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && (ENA_VEC_INTRINSIC)
69	    long vl;
70	    long out_shift2 = 30 - out_shift;
71	
72	    for (long i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
73	    {
74	        long base_idx_y = (i_out_y * stride_y) - pad_y;
75	        // ker_weight start position: (base_idx_y + ker_y_start) >= 0
76	        long ker_y_start = MAX(0, -base_idx_y);
77	        // ker_weight end position: (base_idx_y + ker_y_end) < in_tensor_dim_y
78	        long ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);
79	
80	        for (long i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
81	        {
82	            long base_idx_x = (i_out_x * stride_x) - pad_x;
83	            // ker_weight start position: (base_idx_x + ker_x_start) >= 0
84	            long ker_x_start = MAX(0, -base_idx_x);
85	            // ker_weight end position: (base_idx_x + ker_x_end) < in_tensor_dim_x
86	            long ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
87	
88	            int32_t *bias2 = (int32_t *)bias;
89	
90	            for (long i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
91	            {
92	                long i_ch_mult = 0;
93	                int ch_mult_rest = ch_mult;
94	                for (; i_ch_mult < ch_mult; i_ch_mult += vl)
95	                {
96	                    long idx_out_ch = i_ch_mult + i_input_ch * ch_mult;
97	                    vl = __riscv_vsetvl_e32m8(ch_mult_rest);
98	                    vint32m8_t vBias2 = __riscv_vle32_v_i32m8(bias2, vl);
99	                    bias2 += vl;
100	
101	                    vl = __riscv_vsetvl_e16m4(ch_mult_rest);
102	                    for (long i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
103	                    {
104	                        long idx_y = base_idx_y + i_ker_y;
105	                        long ker_idx_0 = (i_ker_y * ker_dim_x + ker_x_start) * (in_tensor_ch * ch_mult) + idx_out_ch;
106	                        uint8_t *kernel_ptr = (uint8_t *)&ker_weight[ker_idx_0];
107	
108	                        long idx_x = base_idx_x + ker_x_start;
109	                        long idx_0 = (idx_y * in_tensor_dim_x + idx_x) * in_tensor_ch + i_input_ch;
110	                        uint8_t *in_ptr = (uint8_t *)&in_tensor[idx_0];
111	                        long i_ker_x;
112	                        for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
113	                        {
114	                            long in = *in_ptr + in_offset;
115	                            vuint8m2_t vKernelPtr = __riscv_vle8_v_u8m2(kernel_ptr, vl);
116	                            vuint16m4_t vKernelPtrExt = __riscv_vzext_vf2(vKernelPtr, vl);
117	                            vKernelPtrExt = __riscv_vadd(vKernelPtrExt, ker_offset, vl);
118	                            vint16m4_t vKernelPtrExtSigned = __riscv_vreinterpret_i16m4(vKernelPtrExt);
119	                            vBias2 = __riscv_vwmacc(vBias2, in, vKernelPtrExtSigned, vl);
120	                            in_ptr += in_tensor_ch;
121	                            kernel_ptr += in_tensor_ch * ch_mult;
122	                        }
123	                    }
124	
125	                    vl = __riscv_vsetvl_e32m8(ch_mult_rest);
126	
127	                    //requantization
128	                    //part-1
129	                    long vl2;
130	                    vl2 = __riscv_vsetvl_e32m4(ch_mult_rest);
131	                    vint32m4_t vBias2Part1 = __riscv_vget_i32m4(vBias2, 0);
132	                    vint64m8_t vOutTensorPart1 = __riscv_vwmul(vBias2Part1, out_scale, vl2);
133	
134	                    vint32m4_t vOutTensorPart1_i32m4 = __riscv_vnsra(vOutTensorPart1, out_shift2, vl2);
135	                    vOutTensorPart1_i32m4 = __riscv_vssra(vOutTensorPart1_i32m4, 1, __RISCV_VXRM_RNU, vl2);
136	
137	                    vOutTensorPart1_i32m4 = __riscv_vadd(vOutTensorPart1_i32m4, out_offset, vl2);
138	                    vOutTensorPart1_i32m4 = __riscv_vmax(vOutTensorPart1_i32m4, act_min, vl2);
139	                    vOutTensorPart1_i32m4 = __riscv_vmin(vOutTensorPart1_i32m4, act_max, vl2);
140	
141	                    vl2 = __riscv_vsetvl_e16m2(vl2);
142	                    vint16m2_t vOutTensorPart1_i16m2 = __riscv_vnsra(vOutTensorPart1_i32m4, 0, vl2);
143	                    vl2 = __riscv_vsetvl_e8m1(vl2);
144	                    vint8m1_t vOutTensorPart1_i8m1 = __riscv_vnsra(vOutTensorPart1_i16m2, 0, vl2);
145	                    vuint8m1_t vOutTensorPart1_u8m1 = __riscv_vreinterpret_u8m1(vOutTensorPart1_i8m1);
146	                    __riscv_vse8(out_tensor, vOutTensorPart1_u8m1, vl2);
147	                    ch_mult_rest -= vl2;
148	                    out_tensor += vl2;
149	
150	                    //part-2
151	                    if(ch_mult_rest > 0)
152	                    {
153	                        vl2 = __riscv_vsetvl_e32m4(ch_mult_rest);
154	                        vint32m4_t vBias2Part2 = __riscv_vget_i32m4(vBias2, 1);
155	                        vint64m8_t vOutTensorPart2 = __riscv_vwmul(vBias2Part2, out_scale, vl2);
156	                        vint32m4_t vOutTensorPart2_i32m4 = __riscv_vnsra(vOutTensorPart2, out_shift2, vl2);
157	                        vOutTensorPart2_i32m4 = __riscv_vssra(vOutTensorPart2_i32m4, 1, __RISCV_VXRM_RNU, vl2);
158	
159	                        vOutTensorPart2_i32m4 = __riscv_vadd(vOutTensorPart2_i32m4, out_offset, vl2);
160	                        vOutTensorPart2_i32m4 = __riscv_vmax(vOutTensorPart2_i32m4, act_min, vl2);
161	                        vOutTensorPart2_i32m4 = __riscv_vmin(vOutTensorPart2_i32m4, act_max, vl2);
162	
163	                        vl2 = __riscv_vsetvl_e16m2(vl2);
164	                        vint16m2_t vOutTensorPart2_i16m2 = __riscv_vnsra(vOutTensorPart2_i32m4, 0, vl2);
165	                        vl2 = __riscv_vsetvl_e8m1(vl2);
166	                        vint8m1_t vOutTensorPart2_i8m1 = __riscv_vnsra(vOutTensorPart2_i16m2, 0, vl2);
167	                        vuint8m1_t vOutTensorPart2_u8m1 = __riscv_vreinterpret_u8m1(vOutTensorPart2_i8m1);
168	                        __riscv_vse8(out_tensor, vOutTensorPart2_u8m1, vl2);
169	                        ch_mult_rest -= vl2;
170	                        out_tensor += vl2;
171	                    }
172	                }
173	            }
174	        }
175	    }
176	#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ELEN64)
177	#ifdef ENA_AGENT_OPT_CONV_DW_HWC_U8_U8_U8_ASYM_BIAS_ANY
178	    long vl;
179	    long out_shift2 = 30 - out_shift;
180	    long vmulh_extra_shift = out_shift2 - 32;
181	
182	    for (long i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
183	    {
184	        long base_idx_y = (i_out_y * stride_y) - pad_y;
185	        // ker_weight start position: (base_idx_y + ker_y_start) >= 0
186	        long ker_y_start = MAX(0, -base_idx_y);
187	        // ker_weight end position: (base_idx_y + ker_y_end) < in_tensor_dim_y
188	        long ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);
189	
190	        for (long i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
191	        {
192	            long base_idx_x = (i_out_x * stride_x) - pad_x;
193	            // ker_weight start position: (base_idx_x + ker_x_start) >= 0
194	            long ker_x_start = MAX(0, -base_idx_x);
195	            // ker_weight end position: (base_idx_x + ker_x_end) < in_tensor_dim_x
196	            long ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
197	
198	            int32_t *bias2 = (int32_t *)bias;
199	
200	            for (long i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
201	            {
202	                long i_ch_mult = 0;
203	                int ch_mult_rest = ch_mult;
204	                for (; i_ch_mult < ch_mult; i_ch_mult += vl)
205	                {
206	                    long idx_out_ch = i_ch_mult + i_input_ch * ch_mult;
207	                    NDS_VEC_VSETVLI(vl, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
208	                    NDS_VEC_VLE32_V(NDS_VEC_V0, bias2);
209	                    bias2 += vl;
210	
211	                    NDS_VEC_VSETVLI(vl, ch_mult_rest, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
212	                    for (long i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
213	                    {
214	                        long idx_y = base_idx_y + i_ker_y;
215	                        long ker_idx_0 = (i_ker_y * ker_dim_x + ker_x_start) * (in_tensor_ch * ch_mult) + idx_out_ch;
216	                        uint8_t *kernel_ptr = (uint8_t *)&ker_weight[ker_idx_0];
217	
218	                        long idx_x = base_idx_x + ker_x_start;
219	                        long idx_0 = (idx_y * in_tensor_dim_x + idx_x) * in_tensor_ch + i_input_ch;
220	                        uint8_t *in_ptr = (uint8_t *)&in_tensor[idx_0];
221	                        long i_ker_x;
222	                        for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
223	                        {
224	                            long in = *in_ptr + in_offset;
225	                            NDS_VEC_VLE8_V(NDS_VEC_V12, kernel_ptr);
226	                            NDS_VEC_VZEXT_VF2(NDS_VEC_V8, NDS_VEC_V12);
227	                            NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, ker_offset);
228	                            NDS_VEC_VWMACC_VX(NDS_VEC_V0, in, NDS_VEC_V8);
229	                            in_ptr += in_tensor_ch;
230	                            kernel_ptr += in_tensor_ch * ch_mult;
231	                        }
232	                    }
233	
234	                    NDS_VEC_VSETVLI(vl, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
235	
236	                    if (out_shift2 >= 32)
237	                    {
238	                        //requantization using vmulh (single pass, no widening)
239	                        NDS_VEC_VMULH_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
240	                        if (vmulh_extra_shift > 0)
241	                        {
242	                            NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, vmulh_extra_shift);
243	                        }
244	                        NDS_VEC_VSSRA_VI(NDS_VEC_V0, NDS_VEC_V0, 1);
245	
246	                        NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, out_offset);
247	                        NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, act_min);
248	                        NDS_VEC_VMIN_VX(NDS_VEC_V0, NDS_VEC_V0, act_max);
249	
250	                        long vl2;
251	                        NDS_VEC_VSETVLI(vl2, ch_mult_rest, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
252	                        NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
253	                        NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
254	                        NDS_VEC_VNSRA_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
255	                        NDS_VEC_VSE8_V(NDS_VEC_V0, out_tensor);
256	                        ch_mult_rest -= vl2;
257	                        out_tensor += vl2;
258	                    }
259	                    else
260	                    {
261	                        //requantization fallback (vwmul with part-1/part-2)
262	                        long vl2;
263	                        NDS_VEC_VSETVLI(vl2, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
264	                        NDS_VEC_VWMUL_VX(NDS_VEC_V24, NDS_VEC_V0, out_scale);
265	                        NDS_VEC_VNSRA_WX(NDS_VEC_V24, NDS_VEC_V24, out_shift2);
266	                        NDS_VEC_VSSRA_VI(NDS_VEC_V24, NDS_VEC_V24, 1);
267	
268	                        NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V24, out_offset);
269	                        NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, act_min);
270	                        NDS_VEC_VMIN_VX(NDS_VEC_V24, NDS_VEC_V24, act_max);
271	
272	                        NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
273	                        NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
274	                        NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
275	                        NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
276	                        NDS_VEC_VSE8_V(NDS_VEC_V24, out_tensor);
277	                        ch_mult_rest -= vl2;
278	                        out_tensor += vl2;
279	
280	                        if(ch_mult_rest > 0)
281	                        {
282	                            NDS_VEC_VSETVLI(vl2, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
283	                            NDS_VEC_VWMUL_VX(NDS_VEC_V24, NDS_VEC_V4, out_scale);
284	                            NDS_VEC_VNSRA_WX(NDS_VEC_V24, NDS_VEC_V24, out_shift2);
285	                            NDS_VEC_VSSRA_VI(NDS_VEC_V24, NDS_VEC_V24, 1);
286	
287	                            NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V24, out_offset);
288	                            NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, act_min);
289	                            NDS_VEC_VMIN_VX(NDS_VEC_V24, NDS_VEC_V24, act_max);
290	
291	                            NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
292	                            NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
293	                            NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
294	                            NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
295	                            NDS_VEC_VSE8_V(NDS_VEC_V24, out_tensor);
296	                            ch_mult_rest -= vl2;
297	                            out_tensor += vl2;
298	                        }
299	                    }
300	                }
301	            }
302	        }
303	    }
304	#else
305	    long vl;
306	    long out_shift2 = 30 - out_shift;
307	
308	    for (long i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
309	    {
310	        long base_idx_y = (i_out_y * stride_y) - pad_y;
311	        // ker_weight start position: (base_idx_y + ker_y_start) >= 0
312	        long ker_y_start = MAX(0, -base_idx_y);
313	        // ker_weight end position: (base_idx_y + ker_y_end) < in_tensor_dim_y
314	        long ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);
315	
316	        for (long i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
317	        {
318	            long base_idx_x = (i_out_x * stride_x) - pad_x;
319	            // ker_weight start position: (base_idx_x + ker_x_start) >= 0
320	            long ker_x_start = MAX(0, -base_idx_x);
321	            // ker_weight end position: (base_idx_x + ker_x_end) < in_tensor_dim_x
322	            long ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
323	
324	            int32_t *bias2 = (int32_t *)bias;
325	
326	            for (long i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
327	            {
328	                long i_ch_mult = 0;
329	                int ch_mult_rest = ch_mult;
330	                for (; i_ch_mult < ch_mult; i_ch_mult += vl)
331	                {
332	                    long idx_out_ch = i_ch_mult + i_input_ch * ch_mult;
333	                    NDS_VEC_VSETVLI(vl, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
334	                    NDS_VEC_VLE32_V(NDS_VEC_V0, bias2);
335	                    bias2 += vl;
336	
337	                    NDS_VEC_VSETVLI(vl, ch_mult_rest, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
338	                    for (long i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
339	                    {
340	                        long idx_y = base_idx_y + i_ker_y;
341	                        long ker_idx_0 = (i_ker_y * ker_dim_x + ker_x_start) * (in_tensor_ch * ch_mult) + idx_out_ch;
342	                        uint8_t *kernel_ptr = (uint8_t *)&ker_weight[ker_idx_0];
343	
344	                        long idx_x = base_idx_x + ker_x_start;
345	                        long idx_0 = (idx_y * in_tensor_dim_x + idx_x) * in_tensor_ch + i_input_ch;
346	                        uint8_t *in_ptr = (uint8_t *)&in_tensor[idx_0];
347	                        long i_ker_x;
348	                        for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
349	                        {
350	                            long in = *in_ptr + in_offset;
351	                            NDS_VEC_VLE8_V(NDS_VEC_V12, kernel_ptr);
352	                            NDS_VEC_VZEXT_VF2(NDS_VEC_V8, NDS_VEC_V12);
353	                            NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, ker_offset);
354	                            NDS_VEC_VWMACC_VX(NDS_VEC_V0, in, NDS_VEC_V8);
355	                            in_ptr += in_tensor_ch;
356	                            kernel_ptr += in_tensor_ch * ch_mult;
357	                        }
358	                    }
359	
360	                    NDS_VEC_VSETVLI(vl, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
361	
362	                    //requantization
363	                    //part-1
364	                    long vl2;
365	                    NDS_VEC_VSETVLI(vl2, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
366	                    NDS_VEC_VWMUL_VX(NDS_VEC_V24, NDS_VEC_V0, out_scale);
367	                    NDS_VEC_VNSRA_WX(NDS_VEC_V24, NDS_VEC_V24, out_shift2);
368	                    NDS_VEC_VSSRA_VI(NDS_VEC_V24, NDS_VEC_V24, 1);
369	
370	                    NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V24, out_offset);
371	                    NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, act_min);
372	                    NDS_VEC_VMIN_VX(NDS_VEC_V24, NDS_VEC_V24, act_max);
373	
374	                    NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
375	                    NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
376	                    NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
377	                    NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
378	                    NDS_VEC_VSE8_V(NDS_VEC_V24, out_tensor);
379	                    ch_mult_rest -= vl2;
380	                    out_tensor += vl2;
381	
382	                    //part-2
383	                    if(ch_mult_rest > 0)
384	                    {
385	                        NDS_VEC_VSETVLI(vl2, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
386	                        NDS_VEC_VWMUL_VX(NDS_VEC_V24, NDS_VEC_V4, out_scale);
387	                        NDS_VEC_VNSRA_WX(NDS_VEC_V24, NDS_VEC_V24, out_shift2);
388	                        NDS_VEC_VSSRA_VI(NDS_VEC_V24, NDS_VEC_V24, 1);
389	
390	                        NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V24, out_offset);
391	                        NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, act_min);
392	                        NDS_VEC_VMIN_VX(NDS_VEC_V24, NDS_VEC_V24, act_max);
393	
394	                        NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
395	                        NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
396	                        NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
397	                        NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
398	                        NDS_VEC_VSE8_V(NDS_VEC_V24, out_tensor);
399	                        ch_mult_rest -= vl2;
400	                        out_tensor += vl2;
401	                    }
402	                }
403	            }
404	        }
405	    }
406	#endif
407	#elif defined(ENA_DSP_ISA_64)
408	    int32_t input_offset_dual = NDS_DSP_PKBB16(in_offset, in_offset);
409	    int32_t kernel_offset_dual = NDS_DSP_PKBB16(ker_offset, ker_offset);
410	
411	    for (int32_t i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
412	    {
413	        int32_t base_idx_y = (i_out_y * stride_y) - pad_y;
414	        // ker_weight start position: (base_idx_y + ker_y_start) >= 0
415	        int32_t ker_y_start = MAX(0, -base_idx_y);
416	        // ker_weight end position: (base_idx_y + ker_y_end) < in_tensor_dim_y
417	        int32_t ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);
418	
419	        for (int32_t i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
420	        {
421	            int32_t base_idx_x = (i_out_x * stride_x) - pad_x;
422	            // ker_weight start position: (base_idx_x + ker_x_start) >= 0
423	            int32_t ker_x_start = MAX(0, -base_idx_x);
424	            // ker_weight end position: (base_idx_x + ker_x_end) < in_tensor_dim_x
425	            int32_t ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
426	
427	            for (int32_t i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
428	            {
429	                int32_t i_ch_mult = 0;
430	                for (; (i_ch_mult + 4) <= ch_mult; i_ch_mult += 4)
431	                {
432	                    int32_t idx_out_ch = i_ch_mult + i_input_ch * ch_mult;
433	                    long acc_q31x2_0 = *((long*)(bias + idx_out_ch));
434	                    long acc_q31x2_1 = *((long*)(bias + idx_out_ch + 2));
435	
436	                    for (int32_t i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
437	                    {
438	                        int32_t idx_y = base_idx_y + i_ker_y;
439	                        int32_t i_ker_x;
440	                        for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
441	                        {
442	                            int32_t idx_x = base_idx_x + i_ker_x;
443	                            int32_t idx_0 = (idx_y * in_tensor_dim_x + idx_x) * in_tensor_ch + i_input_ch;
444	                            int32_t ker_idx_0 = (i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + idx_out_ch;
445	
446	                            long input_dual = NDS_DSP_PKBB16(in_tensor[idx_0], in_tensor[idx_0]);
447	                            int32_t ker_q7x4 = *((int32_t*)(ker_weight + ker_idx_0));
448	                            long ker_dual0 = NDS_DSP_ZUNPKD810(ker_q7x4);
449	                            long ker_dual1 = NDS_DSP_ZUNPKD832(ker_q7x4);
450	
451	                            input_dual = NDS_DSP_ADD16(input_dual, input_offset_dual);
452	                            ker_dual0 = NDS_DSP_ADD16(ker_dual0, kernel_offset_dual);
453	                            ker_dual1 = NDS_DSP_ADD16(ker_dual1, kernel_offset_dual);
454	
455	                            long tmp_q31x2_0 = NDS_DSP_SMUL16(input_dual, ker_dual0);
456	                            long tmp_q31x2_1 = NDS_DSP_SMUL16(input_dual, ker_dual1);
457	                            acc_q31x2_0 = NDS_DSP_ADD32(acc_q31x2_0, tmp_q31x2_0);
458	                            acc_q31x2_1 = NDS_DSP_ADD32(acc_q31x2_1, tmp_q31x2_1);
459	                        }
460	                    }
461	
462	                    int32_t acc_0 = acc_q31x2_0,
463	                            acc_1 = (acc_q31x2_0 >> 32),
464	                            acc_2 = acc_q31x2_1,
465	                            acc_3 = (acc_q31x2_1 >> 32);
466	
467	                    // Requantize and clip output into specified range
468	                    acc_0 = nn_requantize(acc_0, out_scale, out_shift);
469	                    acc_0 += out_offset;
470	                    acc_0 = MAX(acc_0, act_min);
471	                    acc_0 = MIN(acc_0, act_max);
472	                    *out_tensor++ = acc_0;
473	
474	                    acc_1 = nn_requantize(acc_1, out_scale, out_shift);
475	                    acc_1 += out_offset;
476	                    acc_1 = MAX(acc_1, act_min);
477	                    acc_1 = MIN(acc_1, act_max);
478	                    *out_tensor++ = acc_1;
479	
480	                    acc_2 = nn_requantize(acc_2, out_scale, out_shift);
481	                    acc_2 += out_offset;
482	                    acc_2 = MAX(acc_2, act_min);
483	                    acc_2 = MIN(acc_2, act_max);
484	                    *out_tensor++ = acc_2;
485	
486	                    acc_3 = nn_requantize(acc_3, out_scale, out_shift);
487	                    acc_3 += out_offset;
488	                    acc_3 = MAX(acc_3, act_min);
489	                    acc_3 = MIN(acc_3, act_max);
490	                    *out_tensor++ = acc_3;
491	                }
492	
493	                for (; i_ch_mult < ch_mult; i_ch_mult += 2)
494	                {
495	                    int32_t idx_out_ch = i_ch_mult + i_input_ch * ch_mult;
496	                    long acc_q31x2_0 = *((long*)(bias + idx_out_ch));
497	
498	                    for (int32_t i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
499	                    {
500	                        int32_t idx_y = base_idx_y + i_ker_y;
501	                        int32_t i_ker_x;
502	                        for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
503	                        {
504	                            int32_t idx_x = base_idx_x + i_ker_x;
505	                            int32_t idx_0 = (idx_y * in_tensor_dim_x + idx_x) * in_tensor_ch + i_input_ch;
506	                            int32_t ker_idx_0 = (i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + idx_out_ch;
507	
508	                            long input_dual = NDS_DSP_PKBB16(in_tensor[idx_0], in_tensor[idx_0]);
509	                            int32_t ker_q7x2 = *((int16_t*)(ker_weight + ker_idx_0));
510	                            long ker_dual0 = NDS_DSP_ZUNPKD810(ker_q7x2);
511	
512	                            input_dual = NDS_DSP_ADD16(input_dual, input_offset_dual);
513	                            ker_dual0 = NDS_DSP_ADD16(ker_dual0, kernel_offset_dual);
514	
515	                            long tmp_q31x2_0 = NDS_DSP_SMUL16(input_dual, ker_dual0);
516	                            acc_q31x2_0 = NDS_DSP_ADD32(acc_q31x2_0, tmp_q31x2_0);
517	                        }
518	                    }
519	
520	                    int32_t acc_0 = acc_q31x2_0,
521	                            acc_1 = (acc_q31x2_0 >> 32);
522	
523	                    // Requantize and clip output into specified range
524	                    acc_0 = nn_requantize(acc_0, out_scale, out_shift);
525	                    acc_0 += out_offset;
526	                    acc_0 = MAX(acc_0, act_min);
527	                    acc_0 = MIN(acc_0, act_max);
528	                    *out_tensor++ = acc_0;
529	
530	                    acc_1 = nn_requantize(acc_1, out_scale, out_shift);
531	                    acc_1 += out_offset;
532	                    acc_1 = MAX(acc_1, act_min);
533	                    acc_1 = MIN(acc_1, act_max);
534	                    *out_tensor++ = acc_1;
535	                }
536	            }
537	        }
538	    }
539	#elif defined(ENA_DSP_ISA)
540	    int32_t input_offset_dual = NDS_DSP_PKBB16(in_offset, in_offset);
541	    int32_t kernel_offset_dual = NDS_DSP_PKBB16(ker_offset, ker_offset);
542	
543	    for (int32_t i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
544	    {
545	        int32_t base_idx_y = (i_out_y * stride_y) - pad_y;
546	        // ker_weight start position: (base_idx_y + ker_y_start) >= 0
547	        int32_t ker_y_start = MAX(0, -base_idx_y);
548	        // ker_weight end position: (base_idx_y + ker_y_end) < in_tensor_dim_y
549	        int32_t ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);
550	
551	        for (int32_t i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
552	        {
553	            int32_t base_idx_x = (i_out_x * stride_x) - pad_x;
554	            // ker_weight start position: (base_idx_x + ker_x_start) >= 0
555	            int32_t ker_x_start = MAX(0, -base_idx_x);
556	            // ker_weight end position: (base_idx_x + ker_x_end) < in_tensor_dim_x
557	            int32_t ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
558	
559	            for (int32_t i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
560	            {
561	                int32_t i_ch_mult = 0;
562	                for (; i_ch_mult < ch_mult; i_ch_mult += 2)
563	                {
564	                    int32_t idx_out_ch = i_ch_mult + i_input_ch * ch_mult;
565	                    int32_t acc_0 = bias[idx_out_ch];
566	                    int32_t acc_1 = bias[idx_out_ch + 1];
567	
568	                    for (int32_t i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
569	                    {
570	                        int32_t idx_y = base_idx_y + i_ker_y;
571	                        int32_t i_ker_x;
572	                        for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x+=2)
573	                        {
574	                            int32_t idx_x = base_idx_x + i_ker_x;
575	                            int32_t idx_0 = (idx_y * in_tensor_dim_x + idx_x) * in_tensor_ch + i_input_ch;
576	                            int32_t ker_idx_0 = (i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + idx_out_ch;
577	
578	                            int32_t input_dual = NDS_DSP_PKBB16(in_tensor[idx_0 + in_tensor_ch], in_tensor[idx_0]);
579	                            int32_t ker_daul1 = NDS_DSP_PKBB16(ker_weight[ker_idx_0 + in_tensor_ch * ch_mult], ker_weight[ker_idx_0]);
580	                            int32_t ker_daul2 = NDS_DSP_PKBB16(ker_weight[ker_idx_0 + in_tensor_ch * ch_mult + 1], ker_weight[ker_idx_0 + 1]);
581	
582	                            input_dual = NDS_DSP_ADD16(input_dual, input_offset_dual);
583	                            ker_daul1 = NDS_DSP_ADD16(ker_daul1, kernel_offset_dual);
584	                            ker_daul2 = NDS_DSP_ADD16(ker_daul2, kernel_offset_dual);
585	
586	                            acc_0 = NDS_DSP_KMADA(acc_0, input_dual, ker_daul1);
587	                            acc_1 = NDS_DSP_KMADA(acc_1, input_dual, ker_daul2);
588	                        }
589	                    }
590	
591	                    // Requantize and clip output into specified range
592	                    acc_0 = nn_requantize(acc_0, out_scale, out_shift);
593	                    acc_0 += out_offset;
594	                    acc_0 = MAX(acc_0, act_min);
595	                    acc_0 = MIN(acc_0, act_max);
596	                    *out_tensor++ = acc_0;
597	
598	                    acc_1 = nn_requantize(acc_1, out_scale, out_shift);
599	                    acc_1 += out_offset;
600	                    acc_1 = MAX(acc_1, act_min);
601	                    acc_1 = MIN(acc_1, act_max);
602	                    *out_tensor++ = acc_1;
603	                }
604	            }
605	        }
606	    }
607	#else
608	    for (int32_t i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
609	    {
610	        int32_t base_idx_y = (i_out_y * stride_y) - pad_y;
611	        for (int32_t i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
612	        {
613	            int32_t base_idx_x = (i_out_x * stride_x) - pad_x;
614	            for (int32_t i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
615	            {
616	                int32_t i_ch_mult = 0;
617	                for (; i_ch_mult < ch_mult; i_ch_mult++)
618	                {
619	                    int32_t idx_out_ch = i_ch_mult + i_input_ch * ch_mult;
620	                    // calculate ker_weight start position
621	                    // (base_idx_x + ker_x_start) >= 0
622	                    // (base_idx_y + ker_y_start) >= 0
623	                    int32_t ker_y_start = MAX(0, -base_idx_y);
624	                    int32_t ker_x_start = MAX(0, -base_idx_x);
625	                    // calculate ker_weight end position
626	                    // (base_idx_x + ker_x_end) < in_tensor_dim_x
627	                    // (base_idx_y + ker_y_end) < in_tensor_dim_y
628	                    int32_t ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);
629	                    int32_t ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
630	                    int32_t acc_0 = bias[idx_out_ch];
631	
632	                    for (int32_t i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
633	                    {
634	                        int32_t idx_y = base_idx_y + i_ker_y;
635	                        for (int32_t i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
636	                        {
637	                            int32_t idx_x = base_idx_x + i_ker_x;
638	                            int32_t idx_0 = (idx_y * in_tensor_dim_x + idx_x) * in_tensor_ch + i_input_ch;
639	                            int32_t ker_idx_0 = (i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + idx_out_ch;
640	
641	                            acc_0 += (in_tensor[idx_0] + in_offset) * (ker_weight[ker_idx_0] + ker_offset);
642	                        }
643	                    }
644	
645	                    // Requantize and clip output into specified range
646	                    acc_0 = nn_requantize(acc_0, out_scale, out_shift);
647	                    acc_0 += out_offset;
648	                    acc_0 = MAX(acc_0, act_min);
649	                    acc_0 = MIN(acc_0, act_max);
650	                    *out_tensor++ = acc_0;
651	                }
652	            }
653	        }
654	    }
655	#endif
656	#endif  //ENA_EMPTY_FUN
657	    return status;
