                        NDS_VEC_VNSRA_WI(NDS_VEC_V24, NDS_VEC_V24, 0);
                        NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
