                            NDS_VEC_VSSRA_VI(NDS_VEC_V24, NDS_VEC_V24, 1);

                            NDS_VEC_VADD_VX(NDS_VEC_V24, NDS_VEC_V24, out_offset);
                            NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, act_min);
                            NDS_VEC_VMIN_VX(NDS_VEC_V24, NDS_VEC_V24, act_max);

                            NDS_VEC_VSETVLI(vl2, vl2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
